const fs = require('fs');
const path = require('path');
const { marked } = require('marked');

const dir = process.argv[2] || './docs';
const files = fs.readdirSync(dir).filter(f => f.endsWith('.md')).sort();

let toc = '<h1>Table of Contents</h1><ul>';
let body = '';

for (const file of files) {
  const md = fs.readFileSync(path.join(dir, file), 'utf8');
  const title = file.replace(/\.md$/, '');
  toc += `<li><a href="#${title}">${title}</a></li>`;
  body += `<h2 id="${title}">${title}</h2>` + marked(md);
}

toc += '</ul>';

const html = `<!doctype html><html><head><meta charset="utf-8"><title>Docs</title></head><body>${toc}${body}</body></html>`;
fs.writeFileSync('combined.html', html);
```
